#include<bits/stdc++.h>
using namespace std;
struct node
{
    int cnt,id;
};
vector<int> mp[400010];
int in[400010],r[400010];
int main()
{
    int n,k;
    int t;
    scanf("%d",&t);
    while(t--)
    {
        scanf("%d%d",&n,&k);
        memset(in,0,sizeof(in));
        memset(r,0,sizeof(r));
        for(int i=1;i<=n;i++)
        {
            mp[i].clear();
        }
        for(int i=1;i<n;i++)
        {
            int x,y;
            scanf("%d%d",&x,&y);
            in[x]++;
            in[y]++;
            mp[x].push_back(y);
            mp[y].push_back(x);
        }
        queue<node> q;
        for(int i=1;i<=n;i++)
        {
            if(in[i]==1)
            {
                q.push((node){1,i});
                r[i]=1;
            }
        }
        int ans=n;
        while(!q.empty())
        {
            node t=q.front();
            q.pop();
            for(int i:mp[t.id])
            {
                in[i]--;
                if(in[i]==1)
                {
                    r[i]=r[t.id]+1;
                    q.push((node){t.cnt+1,i});
                }
            }
        }
        for(int i=1;i<=n;i++)
        {
            if(r[i]<=k)
            {
                ans--;
            }
        }
        printf("%d\n",ans);
    }
    return 0;
}
